// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.reflect.Method;

import org.eclipse.rdf4j.sail.lmdb.benchmark.FoafCliqueQueryCatalog.QueryScenario;
import org.junit.jupiter.api.Test;

class FoafCliqueQueryCatalogTest {

	@Test
	void countOnlyScenariosShouldBeRegisteredWithoutFilters() {
		assertCountOnlyScenario("cycle3CountCityInterest");
		assertCountOnlyScenario("cycle5ValuesCountMailboxHomepage");
	}

	@Test
	void everyScenarioShouldHaveMatchingBenchmarkMethod() throws Exception {
		for (QueryScenario scenario : FoafCliqueQueryCatalog.allScenarios()) {
			Method method = FoafCliqueQueryBenchmark.class.getDeclaredMethod(scenario.benchmarkMethodName());
			assertNotNull(method, "Missing benchmark method for " + scenario.benchmarkMethodName());
			assertTrue(method.getReturnType().equals(long.class),
					"Benchmark method must return long for " + scenario.benchmarkMethodName());
			assertTrue(method.getParameterCount() == 0,
					"Benchmark method must be zero-arg for " + scenario.benchmarkMethodName());
		}
	}

	private static void assertCountOnlyScenario(String benchmarkMethodName) {
		QueryScenario scenario = FoafCliqueQueryCatalog.allScenarios()
				.stream()
				.filter(candidate -> candidate.benchmarkMethodName().equals(benchmarkMethodName))
				.findFirst()
				.orElse(null);
		assertNotNull(scenario, "Missing count-only scenario " + benchmarkMethodName);
		assertTrue(scenario.query().contains("COUNT(*) AS ?resultCount"),
				"Count-only scenario must use a COUNT(*) aggregate: " + benchmarkMethodName);
		assertFalse(scenario.query().contains("FILTER ("),
				"Count-only scenario must not use FILTER: " + benchmarkMethodName);
		assertFalse(scenario.query().contains("ORDER BY"),
				"Count-only scenario must not use ORDER BY: " + benchmarkMethodName);
		assertFalse(scenario.query().contains("DISTINCT"),
				"Count-only scenario must not use DISTINCT: " + benchmarkMethodName);
		assertFalse(scenario.query().contains("GROUP BY"),
				"Count-only scenario must not use GROUP BY: " + benchmarkMethodName);
		assertFalse(scenario.query().contains("HAVING"),
				"Count-only scenario must not use HAVING: " + benchmarkMethodName);
	}
}
